/// Warnings generated during analysis.
#[derive(Debug, Clone)]
pub struct AnalysisWarning {
    pub location: String,
    pub message: String,
    pub code: &'static str,
}

/// Export information.
#[derive(Debug, Clone)]
pub struct ExportInfo {
    pub name: String,
    pub rust_name: String,
    pub type_info: TypeInfo,
}

/// Import information.
#[derive(Debug, Clone)]
pub struct ImportInfo {
    pub path: String,
