    output: String,
    /// Current indentation level
    indent: usize,
    /// Generation options
    #[allow(unused)]
    options: CodegenOptions,
}

impl<'a> RustEmitter<'a> {
    /// Create a new emitter.
    #[must_use]
    pub fn new(source: &'a SourceFile, analysis: &'a AnalysisResult) -> Self {
        Self {
            source,
            analysis,
            imports: Vec::new(),
            output: String::new(),
            indent: 0,
            options: CodegenOptions::default(),
        }
    }

    /// Emit the complete module.
    ///
    /// # Errors
    /// Returns an error if code generation fails.
    pub fn emit(mut self) -> crate::Result<GeneratedModule> {
        self.write_header();
        self.write_types();
        self.write_functions();
        self.write_footer();

        let name = self.source.path.file_stem()
            .and_then(std::ffi::OsStr::to_str)
            .unwrap_or("module")
            .to_string();

        Ok(GeneratedModule {
            name,
            source: self.output,
            imports: self.imports,
            types: Vec::new(),
            functions: Vec::new(),
        })
    }

    /// Write module header with imports.
    fn write_header(&mut self) {
        module::write_header(self);
    }

    /// Write type definitions.
    fn write_types(&mut self) {
        module::write_types(self);
    }

    /// Write function definitions.
    fn write_functions(&mut self) {
        module::write_functions(self);
    }

    /// Write module footer.
    fn write_footer(&mut self) {
        self.push_line("// End of generated code");
    }

    /// Emit a single function definition.
    fn emit_function(&mut self, name: &str, func: &crate::analyzer::FunctionInfo) {
        module::emit_function(self, name, func);
    }

    /// Generate function body from source.
    fn generate_function_body(&mut self, name: &str) {
        stmt::generate_function_body(self, name);
    }

    /// Translate a TypeScript line to Rust.
    fn translate_line(&mut self, line: &str) {
        stmt::translate_line(self, line);
    }

    /// Translate an expression.
    fn translate_expr(&self, expr: &str) -> String {
        ExprTranspiler::new(self).transpile(expr)
    }

    /// Translate a condition.
    fn translate_condition(&self, cond: &str) -> String {
        ExprTranspiler::new(self).transpile_condition(cond)
    }

    fn push_line(&mut self, s: &str) {
        self.output.push_str(s);
        self.output.push('\n');
    }

    fn push_indent(&mut self) {
        for _ in 0..self.indent {
            self.output.push_str("    ");
        }
    }
}

/// Convert camelCase/snake_case to snake_case.
#[must_use]
pub fn to_snake_case(s: &str) -> String {
    utils::to_snake_case(s)
}

//! # Expression Transpiler
//!
//! Transpiles TypeScript expressions to Rust expressions.

use super::{RustEmitter, to_snake_case};

/// Expression kind classification.
#[derive(Debug, Clone, Copy, PartialEq)]
pub enum ExprKind {
    /// Literal value
    Literal,
    /// Identifier/variable
    Identifier,
    /// Binary operation
    BinaryOp,
    /// Unary operation
    UnaryOp,
    /// Function call
    Call,
    /// Property access
    PropertyAccess,
    /// Array literal
    ArrayLiteral,
    /// Object literal
    ObjectLiteral,
    /// Ternary expression
    Ternary,
}

/// Transpiles expressions.
pub struct ExprTranspiler<'a, 'em> {
    emitter: &'em RustEmitter<'a>,
}

impl<'a, 'em> ExprTranspiler<'a, 'em> {
    /// Create a new expression transpiler.
    #[must_use]
    pub fn new(emitter: &'em RustEmitter<'a>) -> Self {
        Self { emitter }
    }

    /// Classify an expression.
    #[must_use]
    pub fn classify(expr: &str) -> ExprKind {
        let expr = expr.trim();

        if expr.starts_with('"') || expr.starts_with('\'') {
            return ExprKind::Literal;
        }
        if expr.parse::<f64>().is_ok() {
            return ExprKind::Literal;
        }
        if expr == "true" || expr == "false" {
            return ExprKind::Literal;
        }
        if expr.contains(" ? ") || (expr.starts_with('(') && expr.contains("?")) {
            return ExprKind::Ternary;
        }
        if Self::find_binary_op(expr).is_some() {
            return ExprKind::BinaryOp;
        }
        if expr.starts_with('!') || expr.starts_with('-') {
            return ExprKind::UnaryOp;
        }
        if expr.contains('(') {
            return ExprKind::Call;
        }
        if expr.starts_with('[') {
            return ExprKind::ArrayLiteral;
        }
        if expr.starts_with('{') {
            return ExprKind::ObjectLiteral;
        }
        if expr.contains('.') && !expr.contains('(') {
            return ExprKind::PropertyAccess;
        }

        ExprKind::Identifier
    }

    /// Transpile an expression to Rust.
    #[must_use]
    pub fn transpile(&self, expr: &str) -> String {
        let expr = expr.trim();

        match Self::classify(expr) {
            ExprKind::Literal => expr.to_string(),
            ExprKind::Identifier => to_snake_case(expr),
            ExprKind::BinaryOp => self.transpile_binary_op(expr),
            ExprKind::UnaryOp => self.transpile_unary_op(expr),
            ExprKind::Call => self.transpile_call(expr),
            ExprKind::PropertyAccess => Self::transpile_property_access(expr),
            ExprKind::ArrayLiteral => self.transpile_array_literal(expr),
            ExprKind::ObjectLiteral => self.transpile_object_literal(expr),
            ExprKind::Ternary => self.transpile_ternary(expr),
        }
    }

    /// Transpile a condition (handles &&, ||, ! specially).
    #[must_use]
    pub fn transpile_condition(&self, cond: &str) -> String {
        let cond = cond.trim();

        // Negation
        if let Some(inner) = cond.strip_prefix('!') {
            return format!("!{}", self.transpile_condition(inner.trim()));
        }

        // Parentheses
        if cond.starts_with('(') && cond.ends_with(')') {
            let inner = &cond[1..cond.len() - 1];
            return format!("({})", self.transpile_condition(inner));
        }

        self.transpile(cond)
    }

    /// Find binary operator in expression.
    #[must_use]
    pub fn find_binary_op(expr: &str) -> Option<&'static str> {
        const OPS: &[&str] = &[
            "+=", "-=", "*=", "/=", "===", "!==", "==", "!=",
            "<=", ">=", "&&", "||", "+", "-", "*", "/", "%",
            ">", "<", "|", "&", "^",
        ];

        OPS.iter().find(|&&op| expr.contains(op)).copied()
    }

    /// Transpile a binary operation.
    #[must_use]
    fn transpile_binary_op(&self, expr: &str) -> String {
        let op = Self::find_binary_op(expr).unwrap_or("+");
        let parts: Vec<&str> = expr.split(op).collect();

        if parts.len() == 2 {
            let left = parts[0].trim();
            let right = parts[1].trim();

            let rust_op = Self::map_operator(op);

            return format!(
                "({} {rust_op} {})",
                self.transpile(left),
                self.transpile(right)
            );
        }

        to_snake_case(expr)
    }

    /// Map TypeScript operator to Rust.
    #[must_use]
    pub fn map_operator(op: &str) -> &'static str {
        match op {
            "===" | "==" => "==",
            "!==" | "!=" => "!=",
            "&&" => "&&",
            "||" => "||",
            "+" | "-" | "*" | "/" | "%" | "|" | "&" | "^" => op,
            "<" | ">" | "<=" | ">=" => op,
            _ => op,
        }
    }

    /// Transpile a unary operation.
    #[must_use]
    fn transpile_unary_op(&self, expr: &str) -> String {
        let expr = expr.trim();
        if let Some(inner) = expr.strip_prefix('!') {
            return format!("!{}", self.transpile(inner.trim()));
        }
        if let Some(inner) = expr.strip_prefix('-') {
            return format!("-{}", self.transpile(inner.trim()));
        }
        to_snake_case(expr)
    }

    /// Transpile a function call.
    #[must_use]
    fn transpile_call(&self, expr: &str) -> String {
        if let Some(paren_pos) = expr.find('(') {
            let func = &expr[..paren_pos];
            let args = expr[paren_pos + 1..]
                .trim_end_matches(')')
                .trim_end_matches(';');

            let rust_func = to_snake_case(func);
            let translated_args: Vec<String> = args.split(',')
                .map(|a| self.transpile(a.trim()))
                .collect();

            return format!("{rust_func}({})", translated_args.join(", "));
        }

        to_snake_case(expr)
    }

    /// Transpile property access.
    #[must_use]
    pub fn transpile_property_access(expr: &str) -> String {
        expr.split('.')
            .map(to_snake_case)
            .collect::<Vec<_>>()
            .join(".")
    }

    /// Transpile an array literal.
    #[must_use]
    fn transpile_array_literal(&self, expr: &str) -> String {
        let inner = expr.trim_start_matches('[').trim_end_matches(']');
        let elements: Vec<String> = inner
            .split(',')
            .map(|e| self.transpile(e.trim()))
            .collect();

        format!("vec![{}]", elements.join(", "))
    }

    /// Transpile an object literal.
    #[must_use]
    fn transpile_object_literal(&self, expr: &str) -> String {
        let inner = expr.trim_start_matches('{').trim_end_matches('}');
        let fields: Vec<String> = inner
            .split(',')
            .filter_map(|f| {
                let f = f.trim();
                if f.is_empty() {
                    return None;
                }
                let parts: Vec<&str> = f.split(':').collect();
                if parts.len() == 2 {
                    let key = parts[0].trim();
                    let value = self.transpile(parts[1].trim());
                    return Some(format!("{key}: {value}"));
                }
                Some(f.to_string())
            })
            .collect();

        format!("{{ {} }}", fields.join(", "))
    }

    /// Transpile a ternary expression.
    #[must_use]
    fn transpile_ternary(&self, expr: &str) -> String {
        let question_pos = expr.find(" ? ")
            .unwrap_or_else(|| expr.find("?(").unwrap_or(0));
        let colon_pos = expr.rfind(" : ")
            .unwrap_or_else(|| expr.rfind(":(").unwrap_or(0));

        if colon_pos > question_pos {
            let condition = self.transpile_condition(&expr[..question_pos]);
            let then_expr = expr[question_pos + 3..colon_pos].trim();
            let else_expr = expr[colon_pos + 3..]
                .trim_end_matches(';')
                .trim_end_matches(')');

            return format!(
                "if {} {{ {} }} else {{ {} }}",
                condition,
                self.transpile(then_expr),
                self.transpile(else_expr)
            );
        }

        to_snake_case(expr)
    }
}

//! # Statement Transpiler
//!
//! Transpiles TypeScript statements to Rust statements.

use super::{RustEmitter, to_snake_case, ExprTranspiler};

/// Extract substring until a closing character.
#[must_use]
pub fn rest_until(s: &str, start: usize, end: char) -> &str {
    if let Some(end_pos) = s[start..].find(end) {
        &s[start..start + end_pos]
    } else {
        &s[start..]
    }
}

/// Transpiles statements.
pub struct StmtTranspiler;

impl StmtTranspiler {
    /// Translate a TypeScript line to Rust.
    #[allow(clippy::too_many_lines)]
    pub fn translate_line(emitter: &mut RustEmitter, line: &str) {
        let trimmed = line.trim();

        if trimmed.is_empty() {
            emitter.push_line("");
            return;
        }

        // Variable declarations
        if trimmed.starts_with("const ") || trimmed.starts_with("let ") {
            Self::translate_binding(emitter, trimmed);
            return;
        }

        // Return statements
        if let Some(expr) = trimmed.strip_prefix("return ") {
            let expr = expr.trim_end_matches(';');
            emitter.push_indent();
            let translated = ExprTranspiler::new(emitter).transpile(expr);
            emitter.push_line(&format!("return {translated};"));
            return;
        }

        // If statements
        if trimmed.starts_with("if ") {
            Self::translate_if(emitter, trimmed);
            return;
        }

        // For loops
        if trimmed.starts_with("for ") {
            Self::translate_for(emitter, trimmed);
            return;
        }

        // Switch statements
        if trimmed.starts_with("switch ") {
            Self::translate_switch(emitter, trimmed);
            return;
        }

        // While loops
        if trimmed.starts_with("while ") {
            Self::translate_while(emitter, trimmed);
            return;
        }

        // Default: expression statements
        emitter.push_indent();
        emitter.push_line(&format!(
            "{};",
            ExprTranspiler::new(emitter).transpile(trimmed.trim_end_matches(';'))
        ));
    }

    /// Translate a variable binding.
    pub fn translate_binding(emitter: &mut RustEmitter, line: &str) {
        let (keyword, rest) = if let Some(r) = line.strip_prefix("const ") {
            ("let", r)
        } else {
            ("let mut", line.strip_prefix("let ").unwrap_or(line))
        };

        let rest = rest.trim_end_matches(';');

        if let Some(eq_pos) = rest.find(" = ") {
            let name_type = &rest[..eq_pos];
            let value = &rest[eq_pos + 3..];

            if let Some(colon_pos) = name_type.find(": ") {
                let name = name_type[..colon_pos].trim();
                let type_hint = name_type[colon_pos + 2..].trim();
                emitter.push_indent();
                let translated = ExprTranspiler::new(emitter).transpile(value);
                emitter.push_line(&format!(
                    "{keyword} {name}: {} = {translated};",
                    Self::parse_type_hint(type_hint)
                ));
            } else {
                let name = name_type.trim();
                emitter.push_indent();
                let translated = ExprTranspiler::new(emitter).transpile(value);
                emitter.push_line(&format!("{keyword} {name} = {translated};"));
            }
        }
    }

    /// Translate an if statement.
    pub fn translate_if(emitter: &mut RustEmitter, line: &str) {
        let rest = line.strip_prefix("if ").unwrap();

        if let Some(brace_pos) = rest.find('{') {
            let condition = rest[..brace_pos].trim();
            let translated = ExprTranspiler::new(emitter).transpile_condition(condition);
            emitter.push_indent();
            emitter.push_line(&format!("if {translated} {{"));
            emitter.indent += 1;
        }
    }

    /// Translate a for loop.
    pub fn translate_for(emitter: &mut RustEmitter, line: &str) {
        if line.contains(" of ") {
            // Iterator-based for loop
            if let Some(of_pos) = line.find(" of ") {
                let binding = &line[5..of_pos].trim();
                let array = rest_until(line, of_pos + 4, ')');
                let var_name = binding
                    .replace("const ", "")
                    .replace("let ", "")
                    .trim()
                    .to_string();

                emitter.push_indent();
                let translated = ExprTranspiler::new(emitter).transpile(array);
                emitter.push_line(&format!("for {var_name} in {translated} {{"));
                emitter.indent += 1;
            }
        } else if line.contains(" = ") {
            // C-style for loop
            let rest = line.strip_prefix("for ").unwrap()
                .trim_start_matches('(')
                .trim_end_matches(')');
            emitter.push_indent();
            let translated = ExprTranspiler::new(emitter).transpile(rest.trim_end_matches(';'));
            emitter.push_line(&format!("for {translated} {{"));
            emitter.indent += 1;
        }
    }

    /// Translate a switch statement.
    pub fn translate_switch(emitter: &mut RustEmitter, line: &str) {
        let rest = line.strip_prefix("switch ").unwrap();

        if let Some(brace_pos) = rest.find('{') {
            let expr = rest[..brace_pos].trim();
            let translated = ExprTranspiler::new(emitter).transpile(expr);
            emitter.push_indent();
            emitter.push_line(&format!("match {translated} {{"));
            emitter.indent += 1;
        }
    }

    /// Translate a while loop.
    pub fn translate_while(emitter: &mut RustEmitter, line: &str) {
        let rest = line.strip_prefix("while ").unwrap();

        if let Some(brace_pos) = rest.find('{') {
            let condition = rest[..brace_pos].trim();
            let translated = ExprTranspiler::new(emitter).transpile_condition(condition);
            emitter.push_indent();
            emitter.push_line(&format!("while {translated} {{"));
            emitter.indent += 1;
        }
    }

    /// Parse a type hint string.
    #[must_use]
    pub fn parse_type_hint(hint: &str) -> String {
        match hint {
            "number" => "f64".to_string(),
            "string" => "String".to_string(),
            "boolean" => "bool".to_string(),
            "i32" | "integer" => "i32".to_string(),
            "usize" => "usize".to_string(),
            "void" | "undefined" => "()".to_string(),
            _ => hint.to_string(),
        }
    }

    /// Generate function body from source.
    #[allow(clippy::too_many_lines)]
    pub fn generate_function_body(emitter: &mut RustEmitter, name: &str) {
        let source = &emitter.source.source;

        for line in source.lines() {
            let trimmed = line.trim();

            // Skip empty lines and comments
            if trimmed.is_empty() || trimmed.starts_with("//") {
                emitter.push_line("");
                continue;
            }

            // Find function body
            if trimmed.contains("function ") && trimmed.contains(name) {
                let body_start = trimmed.find('{').or_else(|| trimmed.find("=>"));
                if let Some(start) = body_start {
                    let body = &trimmed[start + 1..];
                    if body.contains('}') {
                        let cleaned = body.trim_end_matches('}').trim_start_matches('{').trim();
                        Self::translate_line(emitter, &format!("    {cleaned}"));
                    }
                }
            }
        }
    }
}

//! # Module Writer
//!
//! Writes Rust module structure.

use super::RustEmitter;

/// Write module header with imports.
pub fn write_header(emitter: &mut RustEmitter) {
    emitter.push_line("//! Generated from Rune source");
    emitter.push_line("");
    emitter.push_line("use std::collections::HashMap;");
    emitter.push_line("use std::fmt::{self, Write};");
    emitter.push_line("");

    // Add protocol imports for app crate
    if emitter.source.path.to_string_lossy().contains("/app/src/") {
        emitter.push_line("use protocol::{AppState, Filter, Task};");
        emitter.push_line("");
    }
}

/// Write type definitions.
pub fn write_types(emitter: &mut RustEmitter) {
    for (_, info) in emitter.analysis.types.iter() {
        match info {
            crate::analyzer::TypeInfo::Struct(s) => {
                emitter.push_line("");
                emitter.push_line(&s.to_rust());
                emitter.push_line("");
            }
            crate::analyzer::TypeInfo::Enum(e) => {
                emitter.push_line("");
                emitter.push_line(&e.to_rust());
                emitter.push_line("");
            }
            _ => {}
        }
    }
}

/// Write function definitions.
pub fn write_functions(emitter: &mut RustEmitter) {
    for (name, info) in emitter.analysis.types.iter() {
        if let crate::analyzer::TypeInfo::Function(func) = info {
            emit_function(emitter, name, func);
        }
    }
}

/// Emit a single function definition.
pub fn emit_function(
    emitter: &mut RustEmitter,
    name: &str,
    func: &crate::analyzer::FunctionInfo,
) {
    use super::to_snake_case;
    use super::stmt::StmtTranspiler;

    let rust_name = to_snake_case(name);
    let async_prefix = if func.is_async { "async " } else { "" };

    // Build parameter list
    let params: Vec<String> = func.params.iter()
        .map(|(n, t)| format!("{}: {}", to_snake_case(n), t.to_rust_type()))
        .collect();
    let params_str = params.join(", ");

    // Build return type
    let return_type = func.return_type.to_rust_type();

    emitter.push_line("");
    emitter.push_line(&format!("/// Function: {name}"));

    if func.is_async {
        emitter.push_line(&format!(
            "{async_prefix}pub fn {rust_name}({params_str}) -> impl Future<Output = {return_type}> + '_ {{"
        ));
    } else {
        emitter.push_line(&format!("pub fn {rust_name}({params_str}) -> {return_type} {{"));
    }

    emitter.indent += 1;

    // Generate function body based on the source
    StmtTranspiler::generate_function_body(emitter, name);

    emitter.indent -= 1;
    emitter.push_line("}");
    emitter.push_line("");
}

//! # Utilities
//!
//! Shared utility functions for the emitter.

/// Convert camelCase/snake_case to snake_case.
#[must_use]
pub fn to_snake_case(s: &str) -> String {
    let mut result = String::new();
    let chars: Vec<char> = s.chars().collect();

    for (i, c) in chars.iter().enumerate() {
        if c.is_uppercase() {
            if i > 0 && !chars[i - 1].is_uppercase() {
                result.push('_');
            }
            result.push(c.to_ascii_lowercase());
        } else if *c == '-' {
            result.push('_');
        } else {
            result.push(*c);
        }
    }

    // Handle consecutive uppercase (e.g., "URLParser" -> "url_parser")
    let mut final_result = String::new();
    for (i, c) in result.chars().enumerate() {
        if i > 0 && i < result.len() - 1 {
            let prev = result.chars().nth(i - 1);
            let next = result.chars().nth(i + 1);
            if c.is_uppercase() && prev.is_some_and(|p| !p.is_uppercase()) {
                final_result.push('_');
            }
            if c.is_uppercase() && next.is_some_and(|n| n.is_uppercase()) {
                // keep as is
            } else if c.is_uppercase() {
                final_result.push('_');
            }
        }
        final_result.push(c.to_ascii_lowercase());
    }

    final_result.trim_matches('_').to_string()
}

