//! # Subset Validator
//!
//! Validates the zero-overhead TypeScript subset.

mod stmt;
mod expr;
mod types;

use crate::analyzer::context::AnalysisContext;
use super::TypeInfo;

/// Validation error with source location.
#[derive(Debug, Clone)]
pub struct ValidationError {
    pub location: String,
    pub message: String,
    pub code: &'static str,
}

impl std::fmt::Display for ValidationError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "{}: {}", self.location, self.message)
    }
}

/// Validates the zero-overhead TypeScript subset.
#[derive(Debug, Default)]
pub struct SubsetValidator {
    complexity: usize,
}

impl SubsetValidator {
    /// Create a new validator.
    pub fn new() -> Self {
        Self { complexity: 0 }
    }

    /// Validate source file.
    pub fn validate(&mut self, source: &crate::parser::SourceFile) -> crate::Result<()> {
        // Note: Full module validation happens in analyze()
        let mut ctx = AnalysisContext::new(source);
        self.validate_module(&source.ast, &mut ctx)
    }

    /// Validate an entire module.
    pub fn validate_module(
        &mut self,
        module: &swc_ecma_ast::Module,
        ctx: &mut AnalysisContext,
    ) -> crate::Result<()> {
        for item in &module.body {
            self.validate_module_item(item, ctx)?;
        }
        Ok(())
    }

    /// Validate a module item.
    fn validate_module_item(
        &mut self,
        item: &swc_ecma_ast::ModuleItem,
        ctx: &mut AnalysisContext,
    ) -> crate::Result<()> {
        use swc_ecma_ast::*;
        match item {
            ModuleItem::Stmt(Stmt::Decl(decl)) => self.validate_decl(decl, ctx),
            ModuleItem::Stmt(Stmt::Expr(expr)) => self.validate_expr(&expr.expr, ctx),
            ModuleItem::ModuleDecl(decl) => self.validate_module_decl(decl, ctx),
            _ => Ok(()),
        }
    }

    /// Validate a declaration.
    fn validate_decl(
        &mut self,
        decl: &swc_ecma_ast::Decl,
        ctx: &mut AnalysisContext,
    ) -> crate::Result<()> {
        if let Some(err) = super::validator::rules::validate_decl_is_allowed(decl, ctx) {
            return self.error(ctx, err.message);
        }

        match decl {
            Decl::Fn(f) => self.validate_function(&f.function, ctx),
            Decl::Var(v) => {
                self.validate_var_decl(v, ctx)?;
                Ok(())
            }
            Decl::TsInterface(_) => Ok(()),
            Decl::TsTypeAlias(t) => self.validate_ts_type(&t.type_ann, ctx),
            Decl::TsEnum(e) => self.validate_ts_enum(e, ctx),
            Decl::TsModule(_) => Ok(()),
            _ => Ok(()),
        }
    }

    /// Validate a variable declaration.
    fn validate_var_decl(
        &mut self,
        v: &swc_ecma_ast::VarDecl,
        ctx: &mut AnalysisContext,
    ) -> crate::Result<()> {
        for decl in &v.decls {
            if let Some(init) = &decl.init {
                self.validate_expr(init, ctx)?;
            }
        }
        Ok(())
    }

    /// Validate a function.
    fn validate_function(
        &mut self,
        f: &swc_ecma_ast::Function,
        ctx: &mut AnalysisContext,
    ) -> crate::Result<()> {
        self.complexity += 1;
        if self.complexity > 10 {
            ctx.add_warning(
                ctx.current_location(),
                "High cyclomatic complexity detected".into(),
                "complexity",
            );
        }

        let result = f.body.as_ref().map_or(Ok(()), |b| self.validate_stmt(b, ctx));
        self.complexity -= 1;
        result
    }

    /// Validate a statement.
    fn validate_stmt(
        &mut self,
        stmt: &swc_ecma_ast::Stmt,
        ctx: &mut AnalysisContext,
    ) -> crate::Result<()> {
        stmt::validate(self, stmt, ctx)
    }

    /// Validate an expression.
    fn validate_expr(
        &mut self,
        expr: &swc_ecma_ast::Expr,
        ctx: &mut AnalysisContext,
    ) -> crate::Result<()> {
        expr::validate(self, expr, ctx)
    }

    /// Validate a module declaration.
    fn validate_module_decl(
        &self,
        decl: &swc_ecma_ast::ModuleDecl,
        ctx: &mut AnalysisContext,
    ) -> crate::Result<()> {
        if let Some(err) = super::validator::rules::validate_module_decl_is_allowed(decl, ctx) {
            return self.error(ctx, err.message);
        }

        match decl {
            swc_ecma_ast::ModuleDecl::Import(_) => Ok(()),
            swc_ecma_ast::ModuleDecl::Export(e) => self.validate_export(e, ctx),
            _ => Ok(()),
        }
    }

    /// Validate an export.
    fn validate_export(
        &self,
        export: &swc_ecma_ast::ExportDecl,
        ctx: &mut AnalysisContext,
    ) -> crate::Result<()> {
        match export {
            swc_ecma_ast::ExportDecl::Decl(d) => self.validate_decl(d, ctx),
            swc_ecma_ast::ExportDecl::Named(_) => Ok(()),
        }
    }

    /// Validate a TypeScript type annotation.
    fn validate_ts_type(
        &self,
        type_: &swc_ecma_ast::TsType,
        ctx: &mut AnalysisContext,
    ) -> crate::Result<()> {
        types::validate(self, type_, ctx)
    }

    /// Validate a TypeScript enum.
    fn validate_ts_enum(
        &self,
        e: &swc_ecma_ast::TsEnumDecl,
        ctx: &mut AnalysisContext,
    ) -> crate::Result<()> {
        let mut tags: std::collections::HashSet<&str> = std::collections::HashSet::new();
        for member in &e.members {
            let tag = match &member.id {
                swc_ecma_ast::TsEnumMemberId::Str(s) => s.value.as_str(),
                swc_ecma_ast::TsEnumMemberId::Computed(_) => {
                    return self.error(ctx, "Computed enum members are forbidden.".into());
                }
            };
            if !tags.insert(tag) {
                return self.error(ctx, format!("Duplicate enum member: {tag}"));
            }
        }
        Ok(())
    }

    /// Create a validation error.
    fn error(&self, ctx: &mut AnalysisContext, message: String) -> crate::Result<()> {
        Err(crate::RuneError::Analysis {
            location: ctx.current_location(),
            message,
        })
    }
}

//! # Statement Validation
//!
//! Validates statement syntax.

use swc_ecma_ast::*;
use crate::analyzer::context::AnalysisContext;
use super::SubsetValidator;

/// Validate a statement.
pub fn validate(
    validator: &mut SubsetValidator,
    stmt: &Stmt,
    ctx: &mut AnalysisContext,
) -> crate::Result<()> {
    if let Some(err) = super::rules::validate_stmt_is_allowed(stmt, ctx) {
        return validator.error(ctx, err.message);
    }

    match stmt {
        Stmt::Expr(e) => validator.validate_expr(&e.expr, ctx),
        Stmt::If(i) => {
            validator.validate_expr(&i.test, ctx)?;
            validator.validate_stmt(&i.cons, ctx)?;
            i.alt.as_ref().map_or(Ok(()), |a| validator.validate_stmt(a, ctx))
        }
        Stmt::While(w) => {
            validator.validate_expr(&w.test, ctx)?;
            validator.validate_stmt(&w.body, ctx)
        }
        Stmt::For(f) => {
            if let Some(init) = &f.init {
                match init {
                    VarDeclOrExpr::VarDecl(v) => validator.validate_var_decl(v, ctx)?,
                    VarDeclOrExpr::Expr(e) => validator.validate_expr(e, ctx)?,
                }
            }
            if let Some(test) = &f.test {
                validator.validate_expr(test, ctx)?;
            }
            if let Some(update) = &f.update {
                validator.validate_expr(update, ctx)?;
            }
            validator.validate_stmt(&f.body, ctx)
        }
        Stmt::ForIn(f) => {
            validator.validate_expr(&f.right, ctx)?;
            validator.validate_stmt(&f.body, ctx)
        }
        Stmt::ForOf(f) => {
            validator.validate_expr(&f.right, ctx)?;
            validator.validate_stmt(&f.body, ctx)
        }
        Stmt::DoWhile(d) => {
            validator.validate_stmt(&d.body, ctx)?;
            validator.validate_expr(&d.test, ctx)
        }
        Stmt::Switch(s) => validate_switch(validator, s, ctx),
        Stmt::Block(b) => validate_block(validator, b, ctx),
        Stmt::Return(r) => r.value.as_ref().map_or(Ok(()), |e| validator.validate_expr(e, ctx)),
        Stmt::Break(_) | Stmt::Continue(_) | Stmt::Empty(_) | Stmt::Debugger(_) => Ok(()),
        Stmt::Labeled(l) => validator.validate_stmt(&l.body, ctx),
        Stmt::Decl(d) => validator.validate_decl(d, ctx),
        _ => Ok(()),
    }
}

/// Validate a switch statement.
fn validate_switch(
    validator: &mut SubsetValidator,
    s: &SwitchStmt,
    ctx: &mut AnalysisContext,
) -> crate::Result<()> {
    validator.validate_expr(&s.discriminant, ctx)?;
    for case in &s.cases {
        if let Some(test) = &case.test {
            validator.validate_expr(test, ctx)?;
        }
        for item in &case.cons {
            validator.validate_stmt(item, ctx)?;
        }
    }
    Ok(())
}

/// Validate a block statement.
fn validate_block(
    validator: &mut SubsetValidator,
    b: &BlockStmt,
    ctx: &mut AnalysisContext,
) -> crate::Result<()> {
    for stmt in &b.stmts {
        validator.validate_stmt(stmt, ctx)?;
    }
    Ok(())
}

//! # Expression Validation
//!
//! Validates expression syntax and operators.

use swc_ecma_ast::*;
use crate::analyzer::context::AnalysisContext;
use crate::analyzer::TypeInfo;
use super::SubsetValidator;

/// Validate an expression.
#[allow(clippy::too_many_lines)]
pub fn validate(
    validator: &mut SubsetValidator,
    expr: &Expr,
    ctx: &mut AnalysisContext,
) -> crate::Result<()> {
    if let Some(err) = super::rules::validate_expr_is_allowed(expr, ctx) {
        return validator.error(ctx, err.message);
    }

    match expr {
        Expr::Ident(_) | Expr::Await(_) | Expr::Paren(_) => Ok(()),
        Expr::Lit(l) => validate_lit(validator, l, ctx),
        Expr::Bin(b) => validate_bin(validator, b, ctx),
        Expr::Unary(u) => validator.validate_expr(&u.arg, ctx),
        Expr::Update(u) => validator.validate_expr(&u.arg, ctx),
        Expr::Assign(a) => validate_assign(validator, a, ctx),
        Expr::Member(m) => validate_member(validator, m, ctx),
        Expr::Call(c) => validate_call(validator, c, ctx),
        Expr::New(_) => validator.error(ctx, "new is forbidden. Use factory functions.".into()),
        Expr::Arrow(a) => validate_arrow(validator, a, ctx),
        Expr::Fn(f) => validator.validate_function(&f.function, ctx),
        Expr::Class(_) => validator.error(ctx, "Classes are forbidden. Use plain objects.".into()),
        Expr::Seq(s) => validate_seq(validator, s, ctx),
        Expr::Cond(c) => validate_cond(validator, c, ctx),
        Expr::Array(a) => validate_array(validator, a, ctx),
        Expr::Object(o) => validate_object(validator, o, ctx),
        Expr::Tpl(t) => validate_tpl(validator, t, ctx),
        Expr::TaggedTpl(t) => validate_tagged_tpl(validator, t, ctx),
        Expr::TsTypeAssertion(t) => validator.validate_expr(&t.expr, ctx),
        Expr::TsAs(t) => validator.validate_expr(&t.expr, ctx),
        Expr::TsNonNull(t) => validator.validate_expr(&t.expr, ctx),
        Expr::TsSatisfies(t) => validator.validate_expr(&t.expr, ctx),
        Expr::Jsx(_) => Ok(()),
        Expr::Invalid(_) => validator.error(ctx, "Invalid expression.".into()),
        _ => Ok(()),
    }
}

/// Validate a literal.
fn validate_lit(
    validator: &mut SubsetValidator,
    l: &Lit,
    ctx: &mut AnalysisContext,
) -> crate::Result<()> {
    if let Some(err) = super::rules::validate_lit_is_allowed(l, ctx) {
        return validator.error(ctx, err.message);
    }
    Ok(())
}

/// Validate a binary expression.
fn validate_bin(
    validator: &mut SubsetValidator,
    b: &BinExpr,
    ctx: &mut AnalysisContext,
) -> crate::Result<()> {
    validator.validate_expr(&b.left, ctx)?;
    validator.validate_expr(&b.right, ctx)?;
    if let Some(err) = super::rules::validate_bin_op_is_allowed(b.op, ctx) {
        return validator.error(ctx, err.message);
    }
    if matches!(b.op, BinaryOp::Div) {
        ctx.add_warning(
            ctx.current_location(),
            "Integer division inferred. Use explicit float (e.g., x / 2.0) if float division intended.".into(),
            "integer-division",
        );
    }
    Ok(())
}

/// Validate an assignment.
fn validate_assign(
    validator: &mut SubsetValidator,
    a: &AssignExpr,
    ctx: &mut AnalysisContext,
) -> crate::Result<()> {
    validator.validate_expr(&a.left, ctx)?;
    validator.validate_expr(&a.value, ctx)
}

/// Validate a member expression.
fn validate_member(
    validator: &mut SubsetValidator,
    m: &MemberExpr,
    ctx: &mut AnalysisContext,
) -> crate::Result<()> {
    validator.validate_expr(&m.obj, ctx)?;
    if m.computed {
        let obj_type = ctx.infer_type(&m.obj);
        if !matches!(obj_type, Some(TypeInfo::Array(_))) {
            return validator.error(ctx, "Dynamic property access is forbidden. Use Map<K,V>.".into());
        }
    }
    if let Some(prop) = &m.prop {
        validator.validate_expr(prop, ctx)?;
    }
    Ok(())
}

/// Validate a call expression.
fn validate_call(
    validator: &mut SubsetValidator,
    c: &CallExpr,
    ctx: &mut AnalysisContext,
) -> crate::Result<()> {
    validator.validate_expr(&c.callee, ctx)?;
    for arg in &c.args {
        validator.validate_expr(&arg.expr, ctx)?;
    }
    Ok(())
}

/// Validate an arrow function.
fn validate_arrow(
    validator: &mut SubsetValidator,
    a: &ArrowExpr,
    ctx: &mut AnalysisContext,
) -> crate::Result<()> {
    for param in &a.params {
        if let Pat::Assign(assign) = &param.pat {
            validator.validate_expr(&assign.right, ctx)?;
        }
    }
    validator.validate_expr(&a.body, ctx)
}

/// Validate a sequence expression.
fn validate_seq(
    validator: &mut SubsetValidator,
    s: &SeqExpr,
    ctx: &mut AnalysisContext,
) -> crate::Result<()> {
    for e in &s.exprs {
        validator.validate_expr(e, ctx)?;
    }
    Ok(())
}

/// Validate a conditional expression.
fn validate_cond(
    validator: &mut SubsetValidator,
    c: &CondExpr,
    ctx: &mut AnalysisContext,
) -> crate::Result<()> {
    validator.validate_expr(&c.test, ctx)?;
    validator.validate_expr(&c.cons, ctx)?;
    validator.validate_expr(&c.alt, ctx)
}

/// Validate an array expression.
fn validate_array(
    validator: &mut SubsetValidator,
    a: &ArrayLit,
    ctx: &mut AnalysisContext,
) -> crate::Result<()> {
    for elem in &a.elems {
        if let Some(e) = elem {
            validator.validate_expr(&e.expr, ctx)?;
        }
    }
    Ok(())
}

/// Validate an object expression.
fn validate_object(
    validator: &mut SubsetValidator,
    o: &ObjectLit,
    ctx: &mut AnalysisContext,
) -> crate::Result<()> {
    for prop in &o.props {
        match prop {
            PropOrSpread::Prop(p) => validator.validate_prop(p, ctx)?,
            PropOrSpread::Spread(s) => validator.validate_expr(&s.expr, ctx)?,
        }
    }
    Ok(())
}

/// Validate a template literal.
fn validate_tpl(
    validator: &mut SubsetValidator,
    t: &Tpl,
    ctx: &mut AnalysisContext,
) -> crate::Result<()> {
    for e in &t.exprs {
        validator.validate_expr(e, ctx)?;
    }
    Ok(())
}

/// Validate a tagged template.
fn validate_tagged_tpl(
    validator: &mut SubsetValidator,
    t: &TaggedTpl,
    ctx: &mut AnalysisContext,
) -> crate::Result<()> {
    validator.validate_expr(&t.tag, ctx)?;
    for e in &t.tpl.exprs {
        validator.validate_expr(e, ctx)?;
    }
    Ok(())
}

//! # Type Validation
//!
//! Validates TypeScript type annotations.

use swc_ecma_ast::*;
use crate::analyzer::context::AnalysisContext;
use super::SubsetValidator;

/// Validate a TypeScript type annotation.
pub fn validate(
    validator: &SubsetValidator,
    type_: &TsType,
    ctx: &mut AnalysisContext,
) -> crate::Result<()> {
    match type_ {
        TsType::TsKeywordType(k) => validate_keyword(validator, k, ctx),
        TsType::TsArrayType(a) => validator.validate_ts_type(&a.elem_type, ctx),
        TsType::TsTupleType(t) => validate_tuple(validator, t, ctx),
        TsType::TsUnionOrIntersectionType(t) => validate_union(validator, t, ctx),
        TsType::TsParenthesizedType(p) => validator.validate_ts_type(&p.type_ann, ctx),
        TsType::TsFunctionType(f) => validate_function_type(validator, f, ctx),
        TsType::TsTypeRef(t) => validate_type_ref(validator, t, ctx),
        TsType::TsIndexedAccessType(i) => validate_indexed(validator, i, ctx),
        TsType::TsMappedType(_) => validator.error(ctx, "Mapped types are forbidden.".into()),
        _ => Ok(()),
    }
}

/// Validate a keyword type.
fn validate_keyword(
    validator: &SubsetValidator,
    k: &TsKeywordType,
    ctx: &mut AnalysisContext,
) -> crate::Result<()> {
    if let Some(err) = super::rules::validate_ts_keyword_is_allowed(k.kind, ctx) {
        return validator.error(ctx, err.message);
    }
    Ok(())
}

/// Validate a tuple type.
fn validate_tuple(
    validator: &SubsetValidator,
    t: &TsTuple,
    ctx: &mut AnalysisContext,
) -> crate::Result<()> {
    for elem in &t.elem_types {
        validator.validate_ts_type(&elem.ty, ctx)?;
    }
    Ok(())
}

/// Validate a union or intersection type.
fn validate_union(
    validator: &SubsetValidator,
    t: &TsUnionOrIntersectionType,
    ctx: &mut AnalysisContext,
) -> crate::Result<()> {
    for ty in &t.types {
        validator.validate_ts_type(ty, ctx)?;
    }
    Ok(())
}

/// Validate a function type.
fn validate_function_type(
    validator: &SubsetValidator,
    f: &TsFnType,
    ctx: &mut AnalysisContext,
) -> crate::Result<()> {
    for param in &f.params {
        validator.validate_pat(&param.pat, ctx)?;
        if let Some(type_ann) = &param.type_ann {
            validator.validate_ts_type(&type_ann.type_ann, ctx)?;
        }
    }
    if let Some(ret) = &f.type_ann {
        validator.validate_ts_type(&ret.type_ann, ctx)?;
    }
    Ok(())
}

/// Validate a type reference.
fn validate_type_ref(
    validator: &SubsetValidator,
    t: &TsTypeRef,
    ctx: &mut AnalysisContext,
) -> crate::Result<()> {
    if let Some(type_params) = &t.type_params {
        for param in &type_params.params {
            validator.validate_ts_type(param, ctx)?;
        }
    }
    Ok(())
}

/// Validate an indexed access type.
fn validate_indexed(
    validator: &SubsetValidator,
    i: &TsIndexedAccessType,
    ctx: &mut AnalysisContext,
) -> crate::Result<()> {
    validator.validate_ts_type(&i.obj_type, ctx)?;
    validator.validate_ts_type(&i.index_type, ctx)
}

